import vex

from ag2 import GroupChat, GroupChatManager

# Initialize Vex with education policy
vex_client = vex.Client(api_key="your-vex-key")

# Register FERPA monitor hook
@vex_client.hook("education-ferpa")
def ferpa_guardrail(message):
    if vex.pii_detector.detect(message.content, categories=["NAME", "STUDENT_ID"]):
        return vex.Block("Student PII detected - requires parental consent")
    return vex.Approve()

# Apply to AG2 group chat
manager = GroupChatManager(groupchat=GroupChat(agents), message_hooks=[ferpa_guardrail])

import vex

from ag2 import CodeExecutorAgent

@vex_client.hook("education-code-safety")
def safe_code_execution(message):
    if "CodeExecutorAgent" in message.agent_name:
        code = message.content
        if vex.code_scanner.scan(code, rules=["no_exec", "no_system", "no_eval"]):
            return vex.Block("Unsafe code execution blocked for student safety")
        # Check for accessibility in generated HTML
        if "<img" in code and "alt=" not in code:
            return vex.Block("Missing alt text violates Section 508")
    return vex.Approve()

code_agent = CodeExecutorAgent(message_hooks=[safe_code_execution])

import vex

from ag2 import GroupChatManager

@vex_client.hook("education-group-chat")
def group_chat_guardrail(message):
    if message.chat_type == "group":
        # Detect off-topic drift
        if vex.topic_drift_detector.has_drifted(message.conversation_history, topic="education"):
            return vex.Warn("Conversation drifting off-topic - refocus required")

        # Check speaker bias
        speaker_stats = vex.analyze_speakers(message.conversation_history)
        if speaker_stats.dominance > 0.7:
            return vex.Warn("Speaker bias detected - rotate participation")
    return vex.Approve()

manager = GroupChatManager(message_hooks=[group_chat_guardrail])
